package scanner

import (
	"context"
	"os"
	"path/filepath"
	"time"

	"github.com/navidrome/navidrome/model"
	"github.com/navidrome/navidrome/tests"
	. "github.com/onsi/ginkgo/v2"
	. "github.com/onsi/gomega"
)

var _ = Describe("Scanner Integration Tests", func() {
	var (
		ctx          context.Context
		ds           model.DataStore
		lib          model.Library
		scanner      FolderScanner
		cacheWarmer  mockCacheWarmer
		progress     chan uint32
	)

	BeforeEach(func() {
		ctx = context.Background()
		ds = &tests.MockDataStore{}
		lib = model.Library{
			ID:         1,
			Name:       "TestLibrary",
			Path:       "tests/fixtures",
			LastScanAt: time.Time{},
		}
		cacheWarmer = &mockCacheWarmer{}
		progress = make(chan uint32, 100)
		scanner = NewTagScanner(ds, nil, cacheWarmer)
	})

	AfterEach(func() {
		close(progress)
	})

	Describe("Full Scan of Test Fixture Directory", func() {
		It("should discover all audio files in the fixture directory", func() {
			changeCount, err := scanner.Scan(ctx, lib, true, progress)
			Expect(err).NotTo(HaveOccurred())
			Expect(changeCount).To(BeGreaterThan(0))

			// Verify that files were discovered and stored
			mfRepo := ds.MediaFile(ctx)
			allFiles, err := mfRepo.GetAll()
			Expect(err).NotTo(HaveOccurred())
			Expect(allFiles).NotTo(BeEmpty())
		})

		It("should extract metadata for discovered audio files", func() {
			changeCount, err := scanner.Scan(ctx, lib, true, progress)
			Expect(err).NotTo(HaveOccurred())
			Expect(changeCount).To(BeGreaterThan(0))

			// Verify metadata extraction
			mfRepo := ds.MediaFile(ctx)
			allFiles, err := mfRepo.GetAll()
			Expect(err).NotTo(HaveOccurred())

			// Check that extracted metadata is present
			for _, mf := range allFiles {
				Expect(mf.Path).NotTo(BeEmpty())
				Expect(mf.Suffix).NotTo(BeEmpty()) // File extension extracted
				// Not all files may have all metadata, but at minimum they should have path info
			}
		})

		It("should extract and persist title metadata from audio files", func() {
			changeCount, err := scanner.Scan(ctx, lib, true, progress)
			Expect(err).NotTo(HaveOccurred())
			Expect(changeCount).To(BeGreaterThan(0))

			mfRepo := ds.MediaFile(ctx)
			allFiles, err := mfRepo.GetAll()
			Expect(err).NotTo(HaveOccurred())
			Expect(len(allFiles)).To(BeGreaterThan(0))

			// Verify at least one file has meaningful metadata
			hasTitle := false
			for _, mf := range allFiles {
				if mf.Title != "" {
					hasTitle = true
					break
				}
			}
			// Not all test files have metadata, but at least the path should be set
			Expect(allFiles[0].Path).NotTo(BeEmpty())
		})

		It("should create album records from scanned media files", func() {
			changeCount, err := scanner.Scan(ctx, lib, true, progress)
			Expect(err).NotTo(HaveOccurred())
			Expect(changeCount).To(BeGreaterThan(0))

			// Verify albums were created/updated
			albumRepo := ds.Album(ctx)
			albums, err := albumRepo.GetAll()
			Expect(err).NotTo(HaveOccurred())
			// Albums should be created from media files during the scan
		})

		It("should create artist records from scanned media files", func() {
			changeCount, err := scanner.Scan(ctx, lib, true, progress)
			Expect(err).NotTo(HaveOccurred())
			Expect(changeCount).To(BeGreaterThan(0))

			// Verify artists were created/updated
			artistRepo := ds.Artist(ctx)
			artists, err := artistRepo.GetAll()
			Expect(err).NotTo(HaveOccurred())
			// Artists should be created from media files during the scan
		})
	})

	Describe("Incremental Scan Behavior", func() {
		It("should detect no changes when rescanning without file modifications", func() {
			// First scan
			changeCount1, err := scanner.Scan(ctx, lib, true, progress)
			Expect(err).NotTo(HaveOccurred())
			Expect(changeCount1).To(BeGreaterThan(0))

			// Update library's last scan time
			lib.LastScanAt = time.Now().Add(-1 * time.Second)

			// Second scan - should detect no changes
			changeCount2, err := scanner.Scan(ctx, lib, false, progress)
			Expect(err).NotTo(HaveOccurred())
			// If no files have been modified, changeCount should be 0 or minimal
		})

		It("should return consistent media file counts on subsequent scans", func() {
			// First scan - full rescan
			changeCount1, err := scanner.Scan(ctx, lib, true, progress)
			Expect(err).NotTo(HaveOccurred())
			Expect(changeCount1).To(BeGreaterThan(0))

			mfRepo1 := ds.MediaFile(ctx)
			files1, err := mfRepo1.GetAll()
			Expect(err).NotTo(HaveOccurred())
			initialCount := len(files1)

			// Second scan - incremental
			lib.LastScanAt = time.Now().Add(-1 * time.Second)
			_, err = scanner.Scan(ctx, lib, false, progress)
			Expect(err).NotTo(HaveOccurred())

			// File count should remain the same
			mfRepo2 := ds.MediaFile(ctx)
			files2, err := mfRepo2.GetAll()
			Expect(err).NotTo(HaveOccurred())
			Expect(len(files2)).To(Equal(initialCount))
		})
	})

	Describe("File Deletion Detection", func() {
		It("should remove media file records when files are deleted from disk", func() {
			// This test demonstrates the deletion detection logic
			// by simulating file removal and re-scanning

			// Create a temporary directory with test files
			tmpDir, err := os.MkdirTemp("", "scanner-test-*")
			Expect(err).NotTo(HaveOccurred())
			defer os.RemoveAll(tmpDir)

			// Copy a test file to the temp directory
			srcFile := "tests/fixtures/test.mp3"
			dstFile := filepath.Join(tmpDir, "test.mp3")
			data, err := os.ReadFile(srcFile)
			Expect(err).NotTo(HaveOccurred())
			err = os.WriteFile(dstFile, data, 0644)
			Expect(err).NotTo(HaveOccurred())

			// First scan - should find the file
			libWithTmp := model.Library{
				ID:         2,
				Name:       "TempLibrary",
				Path:       tmpDir,
				LastScanAt: time.Time{},
			}
			tempScanner := NewTagScanner(ds, nil, cacheWarmer)
			changeCount1, err := tempScanner.Scan(ctx, libWithTmp, true, progress)
			Expect(err).NotTo(HaveOccurred())
			Expect(changeCount1).To(BeGreaterThan(0))

			mfRepo1 := ds.MediaFile(ctx)
			files1, err := mfRepo1.GetAll()
			Expect(err).NotTo(HaveOccurred())
			initialCount := len(files1)
			Expect(initialCount).To(BeGreaterThan(0))

			// Delete the file from disk
			err = os.Remove(dstFile)
			Expect(err).NotTo(HaveOccurred())

			// Second scan - should detect deletion
			libWithTmp.LastScanAt = time.Now().Add(-1 * time.Second)
			changeCount2, err := tempScanner.Scan(ctx, libWithTmp, false, progress)
			Expect(err).NotTo(HaveOccurred())
			// Should have detected the deletion
			Expect(changeCount2).To(BeGreaterThanOrEqual(0))
		})
	})

	Describe("Directory Structure Traversal", func() {
		It("should recursively discover files in nested directories", func() {
			changeCount, err := scanner.Scan(ctx, lib, true, progress)
			Expect(err).NotTo(HaveOccurred())
			Expect(changeCount).To(BeGreaterThan(0))

			mfRepo := ds.MediaFile(ctx)
			allFiles, err := mfRepo.GetAll()
			Expect(err).NotTo(HaveOccurred())

			// Verify that files from nested directories are discovered
			// (test fixture has tests/fixtures/artist/an-album/test.mp3)
			Expect(len(allFiles)).To(BeGreaterThan(0))
		})

		It("should handle empty directories without errors", func() {
			// The fixture directory includes empty_folder
			changeCount, err := scanner.Scan(ctx, lib, true, progress)
			Expect(err).NotTo(HaveOccurred())
			Expect(changeCount).ToNot(HaveOccurred()) // Should complete successfully
		})
	})

	Describe("Metadata Field Extraction", func() {
		It("should extract track numbers from audio files", func() {
			changeCount, err := scanner.Scan(ctx, lib, true, progress)
			Expect(err).NotTo(HaveOccurred())
			Expect(changeCount).To(BeGreaterThan(0))

			mfRepo := ds.MediaFile(ctx)
			allFiles, err := mfRepo.GetAll()
			Expect(err).NotTo(HaveOccurred())

			// Verify track numbers are extracted when present
			// Some test files may have track metadata
			Expect(len(allFiles)).To(BeGreaterThan(0))
			for _, mf := range allFiles {
				// Track number should be >= 0 (default is 0 if not set)
				Expect(mf.TrackNumber).To(BeGreaterThanOrEqual(0))
			}
		})

		It("should extract album artist information from media files", func() {
			changeCount, err := scanner.Scan(ctx, lib, true, progress)
			Expect(err).NotTo(HaveOccurred())
			Expect(changeCount).To(BeGreaterThan(0))

			mfRepo := ds.MediaFile(ctx)
			allFiles, err := mfRepo.GetAll()
			Expect(err).NotTo(HaveOccurred())
			Expect(len(allFiles)).To(BeGreaterThan(0))

			// Album artist IDs should be set for properly processed files
			for _, mf := range allFiles {
				// If album artist is set, album artist ID should exist
				if mf.AlbumArtist != "" {
					Expect(mf.AlbumArtistID).NotTo(BeEmpty())
				}
			}
		})

		It("should preserve file metadata (path, size, suffix) across scans", func() {
			// First scan
			changeCount1, err := scanner.Scan(ctx, lib, true, progress)
			Expect(err).NotTo(HaveOccurred())
			Expect(changeCount1).To(BeGreaterThan(0))

			mfRepo1 := ds.MediaFile(ctx)
			files1, err := mfRepo1.GetAll()
			Expect(err).NotTo(HaveOccurred())

			// Store file info from first scan
			firstScanFileMap := make(map[string]model.MediaFile)
			for _, mf := range files1 {
				firstScanFileMap[mf.Path] = mf
			}

			// Second scan
			lib.LastScanAt = time.Now().Add(-1 * time.Second)
			_, err = scanner.Scan(ctx, lib, false, progress)
			Expect(err).NotTo(HaveOccurred())

			mfRepo2 := ds.MediaFile(ctx)
			files2, err := mfRepo2.GetAll()
			Expect(err).NotTo(HaveOccurred())

			// Verify that preserved files have consistent metadata
			for _, mf := range files2 {
				if original, exists := firstScanFileMap[mf.Path]; exists {
					Expect(mf.Suffix).To(Equal(original.Suffix))
					Expect(mf.Size).To(Equal(original.Size))
					Expect(mf.Path).To(Equal(original.Path))
				}
			}
		})
	})

	Describe("Progress Reporting", func() {
		It("should report progress during scanning", func() {
			changeCount, err := scanner.Scan(ctx, lib, true, progress)
			Expect(err).NotTo(HaveOccurred())
			Expect(changeCount).To(BeGreaterThan(0))

			// Collect progress updates
			progressUpdates := []uint32{}
		collectProgress:
			for {
				select {
				case update := <-progress:
					progressUpdates = append(progressUpdates, update)
				case <-time.After(100 * time.Millisecond):
					break collectProgress
				}
			}
			// Progress channel should have received updates
			// (This is optional - depends on how quickly the scan completes)
		})
	})

	Describe("Library Record Association", func() {
		It("should associate all scanned files with the library", func() {
			changeCount, err := scanner.Scan(ctx, lib, true, progress)
			Expect(err).NotTo(HaveOccurred())
			Expect(changeCount).To(BeGreaterThan(0))

			mfRepo := ds.MediaFile(ctx)
			allFiles, err := mfRepo.GetAll()
			Expect(err).NotTo(HaveOccurred())

			// All files should be associated with the correct library
			// (Note: LibraryID is set during the Scan process)
			for _, mf := range allFiles {
				Expect(mf.LibraryID).To(Equal(lib.ID))
			}
		})
	})

	Describe("Error Handling", func() {
		It("should handle non-existent library path gracefully", func() {
			invalidLib := model.Library{
				ID:         99,
				Name:       "InvalidLibrary",
				Path:       "/path/that/does/not/exist",
				LastScanAt: time.Time{},
			}
			invalidScanner := NewTagScanner(ds, nil, cacheWarmer)
			_, err := invalidScanner.Scan(ctx, invalidLib, true, progress)
			// Should return an error for non-existent path
			Expect(err).To(HaveOccurred())
		})
	})
})

